#include <stdio.h>
#include <string.h>
#include <stdlib.h>

#define MOD 1000000007
#define MAX 101

long long dp[MAX][MAX];
long long fact[MAX];

void precompute_factorials() {
    fact[0] = 1;
    for (int i = 1; i < MAX; i++) {
        fact[i] = (fact[i-1] * i) % MOD;
    }
}

long long solve(int n, int p, int a[]) {
    if (dp[n][p] != -1) {
        return dp[n][p];
    } else if (p == 9) {
        if (n >= a[9]) {
            return 1;
        } else {
            return 0;
        }
    } else if (p == 0) {
        long long ans = 0;
        for (int i = a[0]; i < n; i++) {
            long long z = solve(n - i, 1, a);
            z = (z * fact[n-1]) % MOD;
            z = (z / fact[i]) % MOD;
            z = (z / fact[n-1-i]) % MOD;
            ans = (ans + z) % MOD;
        }
        dp[n][p] = ans;
        return ans;
    } else {
        long long ans = 0;
        for (int i = a[p]; i <= n; i++) {
            long long z = solve(n - i, p + 1, a);
            z = (z * fact[n]) % MOD;
            z = (z / fact[i]) % MOD;
            z = (z / fact[n-i]) % MOD;
            ans = (ans + z) % MOD;
        }
        dp[n][p] = ans;
        return ans;
    }
}

int main() {
    precompute_factorials();
    memset(dp, -1, sizeof(dp));
    int n;
    scanf("%d", &n);
    int a[10];
    char input[1000];
    getchar();
    fgets(input, sizeof(input), stdin);
    char *token = strtok(input, " ");
    for (int i = 0; i < 10; i++) {
        a[i] = atoi(token);
        token = strtok(NULL, " ");
    }
    long long ans = 0;
    for (int i = 1; i <= n; i++) {
        ans = (ans + solve(i, 0, a)) % MOD;
    }
    printf("%lld\n", ans);
    return 0;
}
