#include <stdio.h>
#include <stdlib.h>
#include <string.h>

#define MOD 1000000007
#define MAX 101

long long dp[MAX][MAX];

long long factorial(int n) {
    long long res = 1;
    for (int i = 2; i <= n; i++) {
        res *= i;
    }
    return res;
}

long long solve(int n, int p, int a[]) {
    if (dp[n][p] != -1) {
        return dp[n][p];
    } else if (p == 9) {
        if (n >= a[9]) {
            return 1;
        } else {
            return 0;
        }
    } else if (p == 0) {
        long long ans = 0;
        for (int i = a[0]; i < n; i++) {
            long long z = solve(n - i, 1, a);
            z *= factorial(n - 1);
            z /= factorial(i);
            z /= factorial(n - 1 - i);
            ans += z;
        }
        dp[n][p] = ans;
        return ans;
    } else {
        long long ans = 0;
        for (int i = a[p]; i <= n; i++) {
            long long z = solve(n - i, p + 1, a);
            z *= factorial(n);
            z /= factorial(i);
            z /= factorial(n - i);
            ans += z;
        }
        dp[n][p] = ans;
        return ans;
    }
}

int main() {
    for (int i = 0; i < MAX; i++) {
        for (int j = 0; j < MAX; j++) {
            dp[i][j] = -1;
        }
    }

    int n;
    scanf("%d", &n);
    int a[10];
    char input[1000];
    getchar();
    fgets(input, sizeof(input), stdin);
    char *token = strtok(input, " ");
    for (int i = 0; i < 10; i++) {
        a[i] = atoi(token);
        token = strtok(NULL, " ");
    }

    long long ans = 0;
    for (int i = 1; i <= n; i++) {
        ans += solve(i, 0, a);
        ans %= MOD;
    }
    printf("%lld\n", ans);

    return 0;
}
